	('7bb6f6b9-683f-4998-b8ad-d042b78abfb8', 'Celebrate 2026 Father’s Day at the Louisville Zoo', 'Treat dad to a day at the Zoo. In celebration of Father’s Day, all fathers receive free Zoo admission on Sunday, June 21.  Enjoy a day exploring exhibits, seeing animals up close and spending quality time together as a family. From favorite Zoo classics to seasonal animal activity, it’s an easy way to celebrate Dad.  How it works   Free admission is available to all fathers on Father’s Day Tickets are available at the Zoo only Valid for standard daytime admission Zoo hours and regular parking fees apply.', '2026-06-21 14:00:00+00', '2026-06-21 21:00:00+00', 'America/New_York', 'Louisville Zoo', NULL, '4f546c98-7985-4127-b472-c43254eb77c3', 38.2051766, -85.7053359, NULL, NULL, NULL, true, 'https://louisvillezoo.org/event/celebrate-2026-fathers-day-at-the-louisville-zoo/', 'Louisville Zoo Events', 'f0386301-e604-479b-bf96-7d55cb4662d5', '["https://louisvillezoo.org/wp-content/uploads/2026/01/PL_Fathers-Day.png"]', 'published', 0.817, NULL, false, 0, '''2026'':2 ''21'':33 ''activ'':58 ''admiss'':29,71,92 ''anim'':40,57 ''appli'':99 ''avail'':73,83 ''celebr'':1,19,65 ''classic'':54 ''close'':42 ''dad'':11,66 ''day'':5,14,23,36,80 ''daytim'':91 ''easi'':62 ''enjoy'':34 ''exhibit'':38 ''explor'':37 ''famili'':50 ''father'':3,21,25,76,78 ''favorit'':52 ''fee'':98 ''free'':27,70 ''hour'':94 ''june'':32 ''louisvill'':8,100 ''park'':97 ''qualiti'':45 ''receiv'':26 ''regular'':96 ''season'':56 ''see'':39 ''spend'':44 ''standard'':90 ''sunday'':31 ''ticket'':81 ''time'':46 ''togeth'':47 ''treat'':10 ''valid'':88 ''way'':63 ''work'':69 ''zoo'':9,17,28,53,86,93,101', '2026-05-10 16:03:04.671324+00', '2026-05-10 19:05:59.085041+00', 'openai', true);
