	('5a040799-e0e1-47f6-ba51-afdf388a58ca', '3ced4730-bc45-4f3a-b147-277d806b9146', '78b8cbbd-eaf6-4df7-be6d-17777e56684b', 'import', 'openai', 'gpt-4o-mini', 'success', 'Zoofari 2026', '| HOME | TICKETS | SPONSORS | FAQS | AUCTION | CONTACT | ADOPTIONS |              Join us in celebrating the 45th annual Zoofari gala, hosted by Friends of the Louisville Zoo, on Friday, June 12, 2026. This year, we are honoring three members of the Louisville Zoo’s majestic family: Masai giraffes Baridi, Kianga, Josie and Nyasi. The night begins with signature cocktails, hors d’oeuvres, dinner, silent auction, a bourbon pull, and live music provided by the Louisville Crashers.  Don’t miss out on special opportunities only available to sponsors, including animal encounters, VIP options, and a unique live auction. There is no other party in town like this!  All proceeds will support the enhancement and expansion of the Louisville Zoo.  Please note that this event is for guests who are 21+ only.                                                                Zoofari is hosted by the Friends of the Louisville Zoo board. The Friends of the Louisville Zoo (FOZ) was established in 1969 and is a 100% volunteer managed 501(c)(3) charitable organization (EIN #61-0721682), raising funds to support the enhancement and expansion of The Louisville Zoo.            ', '["free", "outdoor", "indoor", "toddler-friendly", "baby-friendly", "teen-friendly", "weekend", "educational", "arts-crafts", "music", "sensory-friendly", "family-festival", "storytime", "stem", "sports", "cooking", "nature", "community", "holiday", "playgroup"]', '[{"slug": "music", "reason": "The event features live music provided by the Louisville Crashers.", "confidence": 0.9, "matched_keywords": []}, {"slug": "community", "reason": "The event supports the enhancement and expansion of the Louisville Zoo, benefiting the community.", "confidence": 0.8, "matched_keywords": []}, {"slug": "holiday", "reason": "The event is a gala celebration, which can be considered a festive occasion.", "confidence": 0.7, "matched_keywords": []}, {"slug": "family-festival", "reason": "The event is hosted by a family-oriented organization and celebrates animals, appealing to families.", "confidence": 0.6, "matched_keywords": []}, {"slug": "educational", "reason": "The event involves animal encounters and supports a zoo, which has educational aspects.", "confidence": 0.5, "matched_keywords": []}, {"slug": "outdoor", "reason": "The event is associated with a zoo, which typically has outdoor elements.", "confidence": 0.4, "matched_keywords": []}]', '{"price": null, "age_max": null, "age_min": 21, "is_free": false, "venue_name": null}', 'The event is a gala for adults 21 and over, featuring live music and supporting the zoo, which aligns with community and educational themes.', NULL, 5349, '2026-05-10 16:02:47.570566+00'),
